import{_ as a,c as i,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"核心概念: 统一技能生态 | OpenSkills","description":"学习 OpenSkills 的核心概念和工作原理。作为统一技能加载器，支持多代理共享技能，实现渐进式加载。","frontmatter":{"title":"核心概念: 统一技能生态 | OpenSkills","sidebarTitle":"让 AI 工具共享技能","subtitle":"核心概念: 统一技能生态 | OpenSkills","description":"学习 OpenSkills 的核心概念和工作原理。作为统一技能加载器，支持多代理共享技能，实现渐进式加载。","tags":["概念介绍","核心概念"],"prerequisite":[],"order":2},"headers":[],"relativePath":"zh/numman-ali/openskills/start/what-is-openskills/index.md","filePath":"zh/numman-ali/openskills/start/what-is-openskills/index.md"}'),e={name:"zh/numman-ali/openskills/start/what-is-openskills/index.md"};function n(d,t,r,o,h,p){return s(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="什么是-openskills" tabindex="-1">什么是 OpenSkills？ <a class="header-anchor" href="#什么是-openskills" aria-label="Permalink to &quot;什么是 OpenSkills？&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>理解 OpenSkills 的核心价值和工作原理</li><li>知道 OpenSkills 和 Claude Code 的关系</li><li>判断何时使用 OpenSkills 而不是内置技能系统</li><li>了解如何让多个 AI 编码代理共享技能生态</li></ul><div class="info custom-block"><p class="custom-block-title">前置知识</p><p>本教程假设你了解基本的 AI 编码工具（如 Claude Code、Cursor 等），但不要求你有任何 OpenSkills 使用经验。</p></div><hr><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你可能遇到这些场景：</p><ul><li><strong>在 Claude Code 用顺手的技能，换了 AI 工具就没了</strong>：比如 Claude Code 里的 PDF 处理技能，到了 Cursor 就用不了</li><li><strong>不同工具重复安装技能</strong>：每个 AI 工具都要单独配置技能，管理成本高</li><li><strong>想用私有技能，但官方 Marketplace 不支持</strong>：公司内部或自己开发的技能，无法方便地分享给团队</li></ul><p>这些问题本质上都是：<strong>技能格式不统一，无法跨工具共享</strong>。</p><hr><h2 id="核心思路-统一技能格式" tabindex="-1">核心思路：统一技能格式 <a class="header-anchor" href="#核心思路-统一技能格式" aria-label="Permalink to &quot;核心思路：统一技能格式&quot;">​</a></h2><p>OpenSkills 的核心思想很简单：<strong>把 Claude Code 的技能系统变成通用的技能加载器</strong>。</p><h3 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h3><p><strong>OpenSkills</strong> 是 Anthropic 技能系统的通用加载器，让任何 AI 编码代理（Claude Code、Cursor、Windsurf、Aider 等）都能使用标准的 SKILL.md 格式技能。</p><p>简单说：<strong>一个安装器，服务所有 AI 编码工具</strong>。</p><h3 id="它解决了什么问题" tabindex="-1">它解决了什么问题 <a class="header-anchor" href="#它解决了什么问题" aria-label="Permalink to &quot;它解决了什么问题&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>技能格式不统一</td><td>使用 Claude Code 的标准 SKILL.md 格式</td></tr><tr><td>技能无法跨工具共享</td><td>生成统一的 AGENTS.md，所有工具都能读取</td></tr><tr><td>技能管理分散</td><td>统一的安装、更新、删除命令</td></tr><tr><td>私有技能难分享</td><td>支持从本地路径和私有 git 仓库安装</td></tr></tbody></table><hr><h2 id="核心价值" tabindex="-1">核心价值 <a class="header-anchor" href="#核心价值" aria-label="Permalink to &quot;核心价值&quot;">​</a></h2><p>OpenSkills 提供以下核心价值：</p><h3 id="_1-统一标准" tabindex="-1">1. 统一标准 <a class="header-anchor" href="#_1-统一标准" aria-label="Permalink to &quot;1. 统一标准&quot;">​</a></h3><p>所有代理使用相同的技能格式和 AGENTS.md 描述，无需学习新格式。</p><ul><li><strong>与 Claude Code 完全兼容</strong>：相同的提示格式、相同的 Marketplace、相同的文件夹结构</li><li><strong>标准化的 SKILL.md</strong>：技能定义清晰，易于开发和维护</li></ul><h3 id="_2-渐进式加载" tabindex="-1">2. 渐进式加载 <a class="header-anchor" href="#_2-渐进式加载" aria-label="Permalink to &quot;2. 渐进式加载&quot;">​</a></h3><p>按需加载技能，保持 AI 上下文精简。</p><ul><li>不需要一次性加载所有技能</li><li>AI 代理根据任务需求动态加载相关技能</li><li>避免上下文爆炸，提升响应质量</li></ul><h3 id="_3-多代理支持" tabindex="-1">3. 多代理支持 <a class="header-anchor" href="#_3-多代理支持" aria-label="Permalink to &quot;3. 多代理支持&quot;">​</a></h3><p>一套技能服务多个代理，无需重复安装。</p><ul><li>Claude Code、Cursor、Windsurf、Aider 共享同一套技能</li><li>统一的技能管理界面</li><li>减少配置和维护成本</li></ul><h3 id="_4-开源友好" tabindex="-1">4. 开源友好 <a class="header-anchor" href="#_4-开源友好" aria-label="Permalink to &quot;4. 开源友好&quot;">​</a></h3><p>支持本地路径和私有 git 仓库，适合团队协作。</p><ul><li>从本地文件系统安装技能（开发中）</li><li>从私有 git 仓库安装（公司内部共享）</li><li>技能可以和项目一起版本管理</li></ul><h3 id="_5-本地运行" tabindex="-1">5. 本地运行 <a class="header-anchor" href="#_5-本地运行" aria-label="Permalink to &quot;5. 本地运行&quot;">​</a></h3><p>无数据上传，隐私安全。</p><ul><li>所有技能文件存储在本地</li><li>不依赖云服务，无数据泄露风险</li><li>适合敏感项目和企业环境</li></ul><hr><h2 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h2><p>OpenSkills 的工作流程很简单，分为三步：</p><h3 id="第一步-安装技能" tabindex="-1">第一步：安装技能 <a class="header-anchor" href="#第一步-安装技能" aria-label="Permalink to &quot;第一步：安装技能&quot;">​</a></h3><p>从 GitHub、本地路径或私有 git 仓库安装技能到你的项目。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从 Anthropic 官方仓库安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 从本地路径安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skills</span></span></code></pre></div><p>技能会被安装到项目的 <code>.claude/skills/</code> 目录（默认），或 <code>.agent/skills/</code> 目录（使用 <code>--universal</code> 时）。</p><h3 id="第二步-同步到-agents-md" tabindex="-1">第二步：同步到 AGENTS.md <a class="header-anchor" href="#第二步-同步到-agents-md" aria-label="Permalink to &quot;第二步：同步到 AGENTS.md&quot;">​</a></h3><p>将已安装技能同步到 AGENTS.md 文件，生成 AI 代理可读取的技能列表。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>AGENTS.md 会包含类似这样的 XML：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;pdf&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Comprehensive PDF manipulation toolkit for extracting text and tables...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;project&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="第三步-ai-代理加载技能" tabindex="-1">第三步：AI 代理加载技能 <a class="header-anchor" href="#第三步-ai-代理加载技能" aria-label="Permalink to &quot;第三步：AI 代理加载技能&quot;">​</a></h3><p>当 AI 代理需要使用技能时，通过以下命令加载技能内容：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skill-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>AI 代理会将技能内容动态加载到上下文中，执行任务。</p><hr><h2 id="与-claude-code-的关系" tabindex="-1">与 Claude Code 的关系 <a class="header-anchor" href="#与-claude-code-的关系" aria-label="Permalink to &quot;与 Claude Code 的关系&quot;">​</a></h2><p>OpenSkills 和 Claude Code 是互补关系，不是替代关系。</p><h3 id="格式完全兼容" tabindex="-1">格式完全兼容 <a class="header-anchor" href="#格式完全兼容" aria-label="Permalink to &quot;格式完全兼容&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Claude Code</th><th>OpenSkills</th></tr></thead><tbody><tr><td><strong>提示格式</strong></td><td><code>&lt;available_skills&gt;</code> XML</td><td>相同的 XML</td></tr><tr><td><strong>技能存储</strong></td><td><code>.claude/skills/</code></td><td><code>.claude/skills/</code> (默认)</td></tr><tr><td><strong>技能调用</strong></td><td><code>Skill(&quot;name&quot;)</code> tool</td><td><code>npx openskills read &lt;name&gt;</code></td></tr><tr><td><strong>Marketplace</strong></td><td>Anthropic marketplace</td><td>GitHub (anthropics/skills)</td></tr><tr><td><strong>渐进式加载</strong></td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="使用场景对比" tabindex="-1">使用场景对比 <a class="header-anchor" href="#使用场景对比" aria-label="Permalink to &quot;使用场景对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>推荐工具</th><th>原因</th></tr></thead><tbody><tr><td>只用 Claude Code</td><td>Claude Code 内置</td><td>无需额外安装，官方支持</td></tr><tr><td>多个 AI 工具混用</td><td>OpenSkills</td><td>统一管理，避免重复</td></tr><tr><td>需要私有技能</td><td>OpenSkills</td><td>支持本地和私有仓库</td></tr><tr><td>团队协作</td><td>OpenSkills</td><td>技能可版本管理，易于分享</td></tr></tbody></table><hr><h2 id="安装位置说明" tabindex="-1">安装位置说明 <a class="header-anchor" href="#安装位置说明" aria-label="Permalink to &quot;安装位置说明&quot;">​</a></h2><p>OpenSkills 支持三种安装位置：</p><table tabindex="0"><thead><tr><th>安装位置</th><th>命令</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>项目本地</strong></td><td>默认</td><td>单个项目使用，技能随项目版本管理</td></tr><tr><td><strong>全局安装</strong></td><td><code>--global</code></td><td>所有项目共享常用技能</td></tr><tr><td><strong>Universal 模式</strong></td><td><code>--universal</code></td><td>多代理环境，避免与 Claude Code 冲突</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">什么时候用 Universal 模式？</p><p>如果你同时使用 Claude Code 和其他 AI 编码代理（如 Cursor、Windsurf），使用 <code>--universal</code> 安装到 <code>.agent/skills/</code>，可以让多个代理共享同一套技能，避免冲突。</p></div><hr><h2 id="技能生态系统" tabindex="-1">技能生态系统 <a class="header-anchor" href="#技能生态系统" aria-label="Permalink to &quot;技能生态系统&quot;">​</a></h2><p>OpenSkills 使用与 Claude Code 相同的技能生态系统：</p><h3 id="官方技能库" tabindex="-1">官方技能库 <a class="header-anchor" href="#官方技能库" aria-label="Permalink to &quot;官方技能库&quot;">​</a></h3><p>Anthropic 官方维护的技能仓库：<a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">anthropics/skills</a></p><p>包含常用技能：</p><ul><li>PDF 处理</li><li>图片生成</li><li>数据分析</li><li>等等...</li></ul><h3 id="社区技能" tabindex="-1">社区技能 <a class="header-anchor" href="#社区技能" aria-label="Permalink to &quot;社区技能&quot;">​</a></h3><p>任何 GitHub 仓库都可以作为技能来源，只需包含 SKILL.md 文件即可。</p><h3 id="自定义技能" tabindex="-1">自定义技能 <a class="header-anchor" href="#自定义技能" aria-label="Permalink to &quot;自定义技能&quot;">​</a></h3><p>你可以创建自己的技能，使用标准格式，并与团队共享。</p><hr><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>OpenSkills 的核心思想是：</p><ol><li><strong>统一标准</strong>：使用 Claude Code 的 SKILL.md 格式</li><li><strong>多代理支持</strong>：让所有 AI 编码工具共享技能生态</li><li><strong>渐进式加载</strong>：按需加载，保持上下文精简</li><li><strong>本地运行</strong>：无数据上传，隐私安全</li><li><strong>开源友好</strong>：支持本地和私有仓库</li></ol><p>通过 OpenSkills，你可以：</p><ul><li>在不同 AI 工具间无缝切换</li><li>统一管理所有技能</li><li>使用和分享私有技能</li><li>提升开发效率</li></ul><hr><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../installation/">安装OpenSkills工具</a></strong></p><p>你会学到：</p><ul><li>如何检查 Node.js 和 Git 环境</li><li>使用 npx 或全局安装 OpenSkills</li><li>验证安装是否成功</li><li>解决常见的安装问题</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>核心类型定义</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-24</td></tr><tr><td>技能接口（Skill）</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L6" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-6</td></tr><tr><td>技能位置接口（SkillLocation）</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L8-L12" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>8-12</td></tr><tr><td>安装选项接口（InstallOptions）</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L14-L18" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>14-18</td></tr><tr><td>技能元数据接口（SkillMetadata）</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L20-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>20-24</td></tr></tbody></table><p><strong>关键接口</strong>：</p><ul><li><code>Skill</code>：已安装的技能信息（name, description, location, path）</li><li><code>SkillLocation</code>：技能查找位置信息（path, baseDir, source）</li><li><code>InstallOptions</code>：安装命令选项（global, universal, yes）</li><li><code>SkillMetadata</code>：技能元数据（name, description, context）</li></ul><p><strong>核心概念来源</strong>：</p><ul><li>README.md:22-86 - &quot;What Is OpenSkills?&quot; 章节</li></ul></details>`,86)])])}const u=a(e,[["render",n]]);export{c as __pageData,u as default};
